using namespace std;

double solve() {
    // TODO: implement
    int n;
    long long W;
    if(!(cin >> n)) return 0;
    cin >> W;
    vector<long long> v(n), w(n);
    for(int i=0;i<n;i++) cin >> v[i];
    for(int i=0;i<n;i++) cin >> w[i];
    vector<pair<double,int>> ratio(n);
    for(int i=0;i<n;i++) ratio[i] = { (double)v[i]/w[i], i };
    sort(ratio.begin(), ratio.end(), [&](const auto& a, const auto& b){ return a.first > b.first; });
    double ans = 0.0;
    long long remaining = W;
    for(auto &p: ratio){
        int i = p.second;
        if(remaining==0) break;
        if(w[i] <= remaining){
            ans += v[i];
            remaining -= w[i];
        } else {
            ans += (double)v[i] * remaining / w[i];
            remaining = 0;
        }
    }
    cout.setf(ios::fixed); cout<<setprecision(6)<<ans<<"\n";
    return ans;
}

